#!/usr/bin/env python3
"""Port Doctor: a small CLI for tracking and freeing up local dev ports."""

import argparse
import json
import sys
from pathlib import Path

import psutil

# Store reservations in the user's home directory.
CONFIG_FILE = Path.home() / ".port-doctor.json"


# --------------------------------------------------------------------------
# Persistence
# --------------------------------------------------------------------------

def load_reservations() -> dict:
    """Load reserved ports from the config file."""
    if not CONFIG_FILE.exists():
        return {}
    try:
        with open(CONFIG_FILE, "r") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            raise ValueError("top-level JSON must be an object")
        return data
    except (json.JSONDecodeError, ValueError):
        print(f"Warning: {CONFIG_FILE} contains invalid data; ignoring it.")
        return {}
    except OSError as e:
        print(f"Error: could not read {CONFIG_FILE}: {e}")
        sys.exit(1)


def save_reservations(reservations: dict) -> None:
    """Save reserved ports to the config file."""
    try:
        with open(CONFIG_FILE, "w") as f:
            json.dump(reservations, f, indent=4)
    except OSError as e:
        print(f"Error: could not write to {CONFIG_FILE}: {e}")
        sys.exit(1)


# --------------------------------------------------------------------------
# Port scanning
# --------------------------------------------------------------------------

def get_listening_processes() -> tuple:
    """
    Scan every process for listening INET sockets.

    Returns (listening, skipped):
      listening -- {port: psutil.Process}
      skipped   -- number of processes that couldn't be inspected (permissions)

    Walks processes one at a time instead of using the one-shot
    psutil.net_connections(), so a permission error reading one process
    (common for other users'/system processes on macOS, Linux and Windows)
    only excludes that process instead of aborting the whole scan.
    """
    listening = {}
    skipped = 0

    # psutil >= 6.0 renamed Process.connections() to net_connections().
    # Support both so this still works on older psutil installs.
    method_name = "net_connections" if hasattr(psutil.Process, "net_connections") else "connections"

    for proc in psutil.process_iter():
        try:
            conns = getattr(proc, method_name)(kind="inet")
        except psutil.AccessDenied:
            skipped += 1
            continue
        except (psutil.NoSuchProcess, psutil.ZombieProcess):
            continue

        for conn in conns:
            if conn.status == psutil.CONN_LISTEN and conn.laddr:
                listening[conn.laddr.port] = proc

    return listening, skipped


def get_process_on_port(port: int):
    """Return the psutil.Process listening on `port`, or None if it's free (or inaccessible)."""
    listening, _ = get_listening_processes()
    return listening.get(port)


def process_label(proc: psutil.Process) -> str:
    """Human-readable label for a process, tolerant of it having disappeared or being restricted."""
    try:
        return f"'{proc.name()}' (PID: {proc.pid})"
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        return f"PID {proc.pid}"


def port_type(value: str) -> int:
    """argparse `type=` helper: parses and range-checks a port number."""
    try:
        port = int(value)
    except ValueError:
        raise argparse.ArgumentTypeError(f"'{value}' is not a valid integer")
    if not 1 <= port <= 65535:
        raise argparse.ArgumentTypeError(f"port must be between 1 and 65535 (got {port})")
    return port


def confirm(prompt: str) -> bool:
    """Ask a yes/no question. Missing input (e.g. a non-interactive session) counts as 'no'."""
    try:
        return input(f"{prompt} [y/N] ").strip().lower() == "y"
    except EOFError:
        return False


# --------------------------------------------------------------------------
# Commands
# --------------------------------------------------------------------------

def cmd_list(args: argparse.Namespace) -> None:
    """List all reserved ports and their current status."""
    reservations = load_reservations()

    print("\n--- Port Reservations ---")
    if not reservations:
        print("No ports currently reserved.")
    else:
        listening, _ = get_listening_processes()
        for port_str in sorted(reservations, key=int):
            task = reservations[port_str]
            proc = listening.get(int(port_str))
            status = f"IN USE by {process_label(proc)}" if proc else "FREE"
            print(f"Port {port_str:<5} | Task: {task:<20} | Status: {status}")
    print("-------------------------\n")


def cmd_reserve(args: argparse.Namespace) -> None:
    """Reserve a port for a specific task."""
    reservations = load_reservations()
    port_str = str(args.port)

    existing = reservations.get(port_str)
    if existing and existing != args.task and not args.force:
        if not confirm(f"Port {args.port} is already reserved for '{existing}'. Overwrite with '{args.task}'?"):
            print("Aborted.")
            return

    reservations[port_str] = args.task
    save_reservations(reservations)
    print(f"Success: Port {args.port} reserved for '{args.task}'.")


def cmd_unreserve(args: argparse.Namespace) -> None:
    """Remove a port reservation."""
    reservations = load_reservations()
    port_str = str(args.port)

    if port_str in reservations:
        del reservations[port_str]
        save_reservations(reservations)
        print(f"Success: Port {args.port} is no longer reserved.")
    else:
        print(f"Port {args.port} was not reserved.")


def cmd_free(args: argparse.Namespace) -> None:
    """Kill whatever process is listening on the specified port."""
    proc = get_process_on_port(args.port)

    if not proc:
        print(f"Port {args.port} is already free.")
        return

    label = process_label(proc)

    if not args.yes and not confirm(f"Kill {label} on port {args.port}?"):
        print("Aborted.")
        return

    try:
        proc.terminate()
        proc.wait(timeout=3)
        print(f"Success: Freed port {args.port} (killed {label}).")
    except psutil.NoSuchProcess:
        print(f"Success: Freed port {args.port} ({label} had already exited).")
    except psutil.AccessDenied:
        print(f"Error: permission denied to kill {label}. Try running as Administrator/root.")
    except psutil.TimeoutExpired:
        try:
            proc.kill()
            print(f"Success: Force-killed {label} on port {args.port}.")
        except psutil.NoSuchProcess:
            print(f"Success: Freed port {args.port} ({label} exited during shutdown).")
        except psutil.AccessDenied:
            print(f"Error: permission denied to force-kill {label}.")


def cmd_active(args: argparse.Namespace) -> None:
    """Scan and list all currently listening ports on the system."""
    print("\n--- All Active Listening Ports ---")
    listening, skipped = get_listening_processes()

    if not listening:
        print("No listening ports detected.")
    else:
        for port in sorted(listening):
            print(f"Port {port:<5} | IN USE by {process_label(listening[port])}")

    if skipped:
        print(f"\n({skipped} process(es) couldn't be inspected due to permissions; "
              f"run with sudo/Administrator to see those too.)")
    print("----------------------------------\n")


# --------------------------------------------------------------------------
# CLI wiring
# --------------------------------------------------------------------------

def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="Port Doctor: A CLI tool to manage and reserve local ports.")
    subparsers = parser.add_subparsers(dest="command", help="Available commands")

    p_list = subparsers.add_parser("list", help="List all reserved ports and their status")
    p_list.set_defaults(func=cmd_list)

    p_reserve = subparsers.add_parser("reserve", help="Reserve a port for a task")
    p_reserve.add_argument("port", type=port_type, help="The port number to reserve (1-65535)")
    p_reserve.add_argument("task", type=str, help="Description of the task/tool (e.g., 'Claude Code')")
    p_reserve.add_argument("-f", "--force", action="store_true", help="Overwrite an existing reservation without asking")
    p_reserve.set_defaults(func=cmd_reserve)

    p_unreserve = subparsers.add_parser("unreserve", help="Remove a port reservation")
    p_unreserve.add_argument("port", type=port_type, help="The port number to unreserve")
    p_unreserve.set_defaults(func=cmd_unreserve)

    p_free = subparsers.add_parser("free", help="Kill the process using a specific port")
    p_free.add_argument("port", type=port_type, help="The port number to free up")
    p_free.add_argument("-y", "--yes", action="store_true", help="Don't ask for confirmation before killing")
    p_free.set_defaults(func=cmd_free)

    p_active = subparsers.add_parser("active", help="Scan and list all currently listening ports")
    p_active.set_defaults(func=cmd_active)

    return parser


def main() -> None:
    parser = build_parser()
    args = parser.parse_args()

    if hasattr(args, "func"):
        args.func(args)
    else:
        parser.print_help()


if __name__ == "__main__":
    main()


if __name__ == "__main__":
    try:
        main()
    except KeyboardInterrupt:
        print("\nAborted.")
        sys.exit(130)